SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_rep_paid_mobile (loan_type, op_date, conno, add_loan) AS select tb.loan_type , tb.op_date , tb.conno , tb.add_loan
FROM
(
  SELECT  sc_lon_m_contract.loan_type
         ,  sc_lon_m_contract.begining_of_contract as op_date
         ,  sc_lon_m_contract.loan_contract_no as conno 
         ,  sc_lon_m_contract.real_recieve  as add_loan
    FROM sc_lon_m_contract
   WHERE 1=1         
   AND   sc_lon_m_contract.real_recieve > 0  


union all



 SELECT    sc_lon_m_contract.loan_type
         , sc_mobile_recv_msg.effect_date as op_date  
         , sc_lon_m_contract.loan_contract_no as conno 
         ,( sc_mobile_recv_msg.trans_amount + sc_mobile_recv_msg.trans_fee ) as add_loan  
    FROM sc_lon_m_contract,           
         sc_mobile_recv_msg  
   WHERE 1=1  
   AND   sc_lon_m_contract.loan_contract_no = sc_mobile_recv_msg.from_account_no          
   AND   sc_mobile_recv_msg.method_uri  = 'ADDLOAN' 
   AND   sc_mobile_recv_msg.confirm_status in ('1','F')      


)  tb
,sc_lon_m_rule 
where sc_lon_m_rule.loan_type = tb.loan_type
and sc_lon_m_rule.atm_status = '1'
/*WHERE*/

--and sc_lon_m_rule.loan_type = '03'
--and tb.op_date  between '1/6/2023' and '30/6/2023'
ORDER BY tb.op_date ASC
,tb.conno ASC;

